138→interface EditSnippetViewProps {
139→  snippet?: SnippetEntry;
140→  onSubmit: (form: SnippetFormState) => void;
141→}
142→
143→function EditSnippetView({ snippet, onSubmit }: EditSnippetViewProps) {
144→  const [form, setForm] = useState<SnippetFormState>(() => {
145→    if (snippet) {
146→      return {
147→        name: snippet.name,
148→        keyword: snippet.keyword,
149→        snippet: snippet.content,
150→        category: snippet.category,
151→        tags: snippet.tags.map(t => t.text.toLowerCase()),
152→      };
153→    }
154→    return INITIAL_SNIPPET_FORM;
155→  });
156→  const [errors, setErrors] = useState<
157→    Partial<Record<keyof SnippetFormState, string>>
158→  >({});
159→
160→  const handleSubmit = useCallback(() => {
161→    const newErrors: Partial<Record<keyof SnippetFormState, string>> = {};
162→    if (!form.name.trim()) {
163→      newErrors.name = 'Name is required';
164→    }
165→    if (!form.snippet.trim()) {
166→      newErrors.snippet = 'Snippet content is required';
167→    }
168→    setErrors(newErrors);
169→    if (Object.keys(newErrors).length > 0) return;
170→    onSubmit(form);
171→  }, [
172→    form,
173→    onSubmit,
174→  ]);
175→
176→  useKeyboardShortcut(
177→    {
178→      key: 'Enter',
179→      meta: true,
180→    },
181→    handleSubmit,
182→  );
183→
184→  return (
185→    <Form onSubmit={handleSubmit}>
186→      <FormTextField
187→        label="Name"
188→        value={form.name}
189→        onChange={v =>
190→          setForm(prev => ({
191→            ...prev,
192→            name: v,
193→          }))
194→        }
195→        placeholder="e.g. Email Signature"
196→        error={errors.name}
197→        autoFocus
198→      />
199→      <FormTextField
200→        label="Keyword"
201→        value={form.keyword}
202→        onChange={v =>
203→          setForm(prev => ({
204→            ...prev,
205→            keyword: v,
206→          }))
207→        }
