276→    }
277→    if (query) {
278→      const lower = query.toLowerCase();
279→      items = items.filter(
280→        e =>
281→          e.name.toLowerCase().includes(lower) ||
282→          e.keyword.toLowerCase().includes(lower) ||
283→          e.content.toLowerCase().includes(lower),
284→      );
